import{_ as i,o as e,c as l,ag as r}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"常见问题（FAQ）","description":"","frontmatter":{},"headers":[],"relativePath":"support/faq.md","filePath":"support/faq.md"}'),t={name:"support/faq.md"};function o(h,a,s,n,d,c){return e(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="常见问题-faq" tabindex="-1">常见问题（FAQ） <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题（FAQ）&quot;">​</a></h1><h2 id="账号与-key" tabindex="-1">账号与 Key <a class="header-anchor" href="#账号与-key" aria-label="Permalink to &quot;账号与 Key&quot;">​</a></h2><h3 id="_1-可以开发票对吧" tabindex="-1">1. 可以开发票对吧？ <a class="header-anchor" href="#_1-可以开发票对吧" aria-label="Permalink to &quot;1. 可以开发票对吧？&quot;">​</a></h3><p>对。支持普票、专票。实际消费满500元可提交开发票需求。</p><h3 id="_2-key-无效-鉴权失败怎么办" tabindex="-1">2. Key 无效/鉴权失败怎么办？ <a class="header-anchor" href="#_2-key-无效-鉴权失败怎么办" aria-label="Permalink to &quot;2. Key 无效/鉴权失败怎么办？&quot;">​</a></h3><ul><li>检查是否复制了多余空格</li><li>检查 Key 是否过期/被禁用</li><li>检查请求是否使用了正确的 Header/参数</li><li>确认使用了对应工具的专用令牌组</li></ul><h3 id="_3-如何查看余额和消费记录" tabindex="-1">3. 如何查看余额和消费记录？ <a class="header-anchor" href="#_3-如何查看余额和消费记录" aria-label="Permalink to &quot;3. 如何查看余额和消费记录？&quot;">​</a></h3><p>登录控制台即可查看：</p><ul><li>当前余额</li><li>充值记录</li><li>消费明细</li><li>账单详情</li></ul><h2 id="网站访问" tabindex="-1">网站访问 <a class="header-anchor" href="#网站访问" aria-label="Permalink to &quot;网站访问&quot;">​</a></h2><h3 id="网站进入为什么白屏" tabindex="-1">网站进入为什么白屏？ <a class="header-anchor" href="#网站进入为什么白屏" aria-label="Permalink to &quot;网站进入为什么白屏？&quot;">​</a></h3><p>很有可能是你的广告过滤插件导致，请手动将我们的域名添加到白名单。</p><p>常见的广告过滤插件：</p><ul><li>AdBlock</li><li>uBlock Origin</li><li>AdGuard</li></ul><p>解决方法：</p><ol><li>打开插件设置</li><li>添加<code>api.ikuncode.cc</code>到白名单</li><li>刷新页面</li></ol><h2 id="环境与安装" tabindex="-1">环境与安装 <a class="header-anchor" href="#环境与安装" aria-label="Permalink to &quot;环境与安装&quot;">​</a></h2><h3 id="npm-安装很慢-失败" tabindex="-1">npm 安装很慢/失败？ <a class="header-anchor" href="#npm-安装很慢-失败" aria-label="Permalink to &quot;npm 安装很慢/失败？&quot;">​</a></h3><p>可以使用国内镜像：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设置淘宝镜像</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://registry.npmmirror.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 验证配置</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry</span></span></code></pre></div><h3 id="node-js-版本过低怎么办" tabindex="-1">Node.js 版本过低怎么办？ <a class="header-anchor" href="#node-js-版本过低怎么办" aria-label="Permalink to &quot;Node.js 版本过低怎么办？&quot;">​</a></h3><p>Claude Code、CodeX 和 Gemini CLI 都需要 Node.js 18+ 版本。</p><p>升级方法：</p><ul><li>Windows: 重新下载安装最新版本</li><li>macOS:<code>brew upgrade node</code></li><li>Linux: 使用 nvm 或 NodeSource 仓库</li></ul><h3 id="环境变量设置后不生效" tabindex="-1">环境变量设置后不生效？ <a class="header-anchor" href="#环境变量设置后不生效" aria-label="Permalink to &quot;环境变量设置后不生效？&quot;">​</a></h3><ul><li>Windows: 重启终端窗口或重启电脑</li><li>macOS/Linux: 执行<code>source ~/.bashrc</code>或<code>source ~/.zshrc</code></li></ul><h2 id="工具使用" tabindex="-1">工具使用 <a class="header-anchor" href="#工具使用" aria-label="Permalink to &quot;工具使用&quot;">​</a></h2><h3 id="cc-switch-无法启动" tabindex="-1">CC-Switch 无法启动？ <a class="header-anchor" href="#cc-switch-无法启动" aria-label="Permalink to &quot;CC-Switch 无法启动？&quot;">​</a></h3><ol><li>检查是否有权限问题</li><li>尝试以管理员身份运行</li><li>查看是否有杀毒软件拦截</li><li>重新下载安装最新版本</li></ol><h3 id="claude-code-提示连接失败" tabindex="-1">Claude Code 提示连接失败？ <a class="header-anchor" href="#claude-code-提示连接失败" aria-label="Permalink to &quot;Claude Code 提示连接失败？&quot;">​</a></h3><p>检查项：</p><ul><li>网络连接是否正常</li><li>API 密钥是否正确</li><li>环境变量是否设置正确</li><li>余额是否充足</li></ul><h3 id="codex-和-claude-code-的令牌不通用" tabindex="-1">CodeX 和 Claude Code 的令牌不通用？ <a class="header-anchor" href="#codex-和-claude-code-的令牌不通用" aria-label="Permalink to &quot;CodeX 和 Claude Code 的令牌不通用？&quot;">​</a></h3><p>是的，不同工具需要不同的令牌组：</p><ul><li>Claude Code: 使用 Claude Code 令牌组</li><li>CodeX: 使用 &quot;codex测试&quot; 令牌组</li><li>Gemini CLI: 使用 Gemini 令牌组</li></ul><p>请在 IkunCode 平台创建对应的专用令牌。</p><h2 id="计费相关" tabindex="-1">计费相关 <a class="header-anchor" href="#计费相关" aria-label="Permalink to &quot;计费相关&quot;">​</a></h2><h3 id="如何计费" tabindex="-1">如何计费？ <a class="header-anchor" href="#如何计费" aria-label="Permalink to &quot;如何计费？&quot;">​</a></h3><ul><li>按实际使用量计费</li><li>不同模型价格不同</li><li>详细计费规则请查看控制台</li></ul><h3 id="余额不足会怎样" tabindex="-1">余额不足会怎样？ <a class="header-anchor" href="#余额不足会怎样" aria-label="Permalink to &quot;余额不足会怎样？&quot;">​</a></h3><ul><li>服务会暂停</li><li>请及时充值以继续使用</li><li>充值后立即恢复服务</li></ul><h3 id="支持退款吗" tabindex="-1">支持退款吗？ <a class="header-anchor" href="#支持退款吗" aria-label="Permalink to &quot;支持退款吗？&quot;">​</a></h3><ul><li>未使用的余额可以申请退款</li><li>已使用的部分不支持退款</li><li>具体政策请咨询客服</li></ul><h2 id="技术问题" tabindex="-1">技术问题 <a class="header-anchor" href="#技术问题" aria-label="Permalink to &quot;技术问题&quot;">​</a></h2><h3 id="代码会被保存吗" tabindex="-1">代码会被保存吗？ <a class="header-anchor" href="#代码会被保存吗" aria-label="Permalink to &quot;代码会被保存吗？&quot;">​</a></h3><p>不会。我们不会存储您的代码内容，仅转发请求和响应。</p><h3 id="是否支持企业使用" tabindex="-1">是否支持企业使用？ <a class="header-anchor" href="#是否支持企业使用" aria-label="Permalink to &quot;是否支持企业使用？&quot;">​</a></h3><p>支持。企业用户可以：</p><ul><li>联系客服获取企业方案</li><li>支持大额充值和发票</li><li>可能享受优惠价格</li></ul><h3 id="如何获得技术支持" tabindex="-1">如何获得技术支持？ <a class="header-anchor" href="#如何获得技术支持" aria-label="Permalink to &quot;如何获得技术支持？&quot;">​</a></h3><h2 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h2><h3 id="遇到技术难题" tabindex="-1">遇到技术难题？ <a class="header-anchor" href="#遇到技术难题" aria-label="Permalink to &quot;遇到技术难题？&quot;">​</a></h3><p>如果遇到启动失败、报错、超时等技术问题，请查看：</p><p>👉 <a href="/support/troubleshooting">疑难杂症排查指南</a> - 详细的错误排查和解决方案</p><h3 id="仍未解决" tabindex="-1">仍未解决？ <a class="header-anchor" href="#仍未解决" aria-label="Permalink to &quot;仍未解决？&quot;">​</a></h3><p>如果上述问题没有解决您的疑问，请：</p><ul><li>加入 Telegram 群组：<a href="https://t.me/ikuncode" target="_blank" rel="noreferrer">https://t.me/ikuncode</a></li><li>查看<a href="/support/after-sales">售前售后</a>联系客服</li></ul>`,57)])])}const k=i(t,[["render",o]]);export{p as __pageData,k as default};
